onClick:
{{
(() => {
  const isDietTag =
    (
      getHelperLists.data.find(
        x => String(x.id) === String(selPicklistType.selectedOptionValue)
      )?.list_code || ""
    ) === "diet_tag";

  const action = isDietTag ? "delete" : radPLReplaceDeleteAction.selectedOptionValue;
  const replaceToId = isDietTag ? null : selPLReplaceWith.selectedOptionValue;

  if (action === "replace" && !replaceToId) {
    showAlert("Select a replacement item first.", "warning");
    return;
  }

  storeValue("plReplaceAction", action === "replace" ? "Replace" : "Delete");
  storeValue("plReplaceToId", replaceToId || null);

  getHelperIngredientImpactCount.run(() => {
    showModal("mdPLReplaceConfirm");
  });
})()
}}
